public boolean isDirectory() {
    if (file != null) {
        return file.isDirectory();
    }

    if (linkFlag == LF_DIR) {
        return true;
    }

    if (isPaxHeader() || isGlobalPaxHeader()) {
        return false;
    }

    if (getName().endsWith("/")) {
        return true;
    }

    return false;
}

