@Test
public void paxHeaderNotConsideredDirectory() throws Exception {
    final TarArchiveInputStream is = getTestStream("/COMPRESS-356.tar");
    try {
        final TarArchiveEntry entry = is.getNextTarEntry();
        assertEquals("package/package.json", entry.getName());
        assertFalse("Pax header should not be considered a directory", entry.isDirectory());
        assertNull(is.getNextTarEntry());
    } finally {
        is.close();
    }
}

@Test
public void globalPaxHeaderNotConsideredDirectory() throws Exception {
    final TarArchiveEntry entry = new TarArchiveEntry("GlobalHead/");
    entry.setLinkFlag(TarConstants.LF_GNUTYPE_LONGNAME);
    assertFalse("Global Pax header should not be considered a directory even with slash", entry.isDirectory());
}

@Test
public void regularFileWithSlashNotDirectory() throws Exception {
    final TarArchiveEntry entry = new TarArchiveEntry("regularfile/");
    entry.setLinkFlag(TarConstants.LF_NORMAL);
    assertTrue("Regular file with trailing slash should be considered a directory", entry.isDirectory());
}
